@app.route('/search', methods=['GET', 'POST'])
def search():
    query = request.args.get('query', type=str)
    if (query is None) or len(query) < 5:
        return redirect(url_for('index'))

    page = request.args.get('page', 1, type=int)

    answers, total = ESQueryObject(index='articles2', doctype='article'). \
        search_(query, fields=['title', 'abstract']).paginate(
        int(page),
        int(current_app.config['POSTS_PER_PAGE'])
    )

    articles = []

    for article in answers:
        print(article)
        if 'date' in article:
            pub_date = datetime.strptime(str(article['date']), '%Y-%m-%dT%H:%M:%S').strftime('Published at %d, %b %Y')
        else:
            pub_date = ''

        articles.append({
            'id': ''.join(e for e in article['doi'] if e.isalnum()),
            'doi': article['doi'],
            'title': article['title'],
            'abstract': article['abstract'],
            'authors': article['authors'],
            'pub_date': pub_date,
            'journal_name': article['journal']['title'],
            'journal_id': article['journal']['url']
        })

    next_url = url_for('search', q=query, page=page + 1) \
        if total > page * current_app.config['POSTS_PER_PAGE'] else None
    prev_url = url_for('search', q=query, page=page - 1) \
        if page > 1 else None

    return render_template('search/search.html', title=query, answers=articles, query=query, counts=total,
                           npages=int(math.ceil(total / current_app.config['POSTS_PER_PAGE'])),
                           page=page)


