@app.route('/journal', methods=['GET'])
def journal():
    id = request.args.get('id', type=str)
    query = request.args.get('query', default='', type=str)

    if id is None:
        return redirect(url_for('index'))

    query = request.args.get('query', '')

    try:
        summary = wikipedia.summary(id + ' (journal)')
        if summary is None:
            summary = wikipedia.summary(id)

        if summary is not None:
            if 'journal' not in summary.split('.')[0]:
                summary = None
    except:
        summary = None

    '''
    n_issue = []
    n_volumes = Article.query.filter_by(journal_id=journal.id).order_by(Article.id).first().volume
    for i in range(1, int(n_volumes) + 1):
        n_issue.append(int(Article.query.filter(Article.journal_id == journal.id, Article.volume == str(i)).order_by(
            Article.id).first().issue))
    print(n_issue)
    '''
    es_condition = ESCondition()

    last_published, total = ESQueryObject(index='articles2', doctype='article'). \
        filter_(es_condition.eql_('journal.title', id)).sort_('date', 'desc').limit_(6)

    return render_template('search/journal.html', title=id, journal=journal, query=query, summary=summary,
                           n_issue=[], last_published=last_published)


@app.route('/article', methods=['GET'])
def article():
    id = request.args.get('id')

    if id is None:
        return redirect(url_for('index'))

    query = request.args.get('query', '')

    article = current_app.elasticsearch.get(index='articles2', doc_type='article', id=id)['_source']

    if article['title'] is None:
        article['title'] = ''

    if article['abstract'] is None:
        article.abstract = ''

    if 'date' in article:
        pub_date = datetime.strptime(str(article['date']), '%Y-%m-%dT%H:%M:%S').strftime('Published at %d, %b %Y')
    else:
        pub_date = ''

    comments = Comment.query.filter_by(article_id=article['doi']).all()
    for comment in comments:
        print(comment.author.name)

    return render_template('search/article.html', title=article['title'], article=article, query=query,
                           pub_date=pub_date, comments=comments)


