@app.route('/comment', methods=['GET', 'POST'])
def comment():
    if current_user is None:
        return redirect('/')

    article_id = request.form.get('article_id', str)
    content = request.form.get('content', str)

    new_comment = Comment(user_id=current_user.id, content=content, article_id=article_id,
                          published=datetime.now())

    db.session.add(new_comment)
    db.session.commit()

    return redirect(url_for('article', id=article_id))


@app.route('/vote')
def vote():
    user = current_user
    if not user: return redirect('/')

    type = request.args.get('type')
    article_id = request.args.get('article_id')
    like = Like(article_id=article_id, type=type, user_id=user.id)

    return redirect(url_for('article', id=article_id))


@app.route('/profile', methods=['GET', 'POST'])
@login_required
def profile():
    form = ProfileForm()
    user = User.query.get(current_user.id)

    if form.validate_on_submit():
        user.name = form.name.data
        user.email = form.email.data
        user.city = form.city.data
        user.country = form.country.data
        user.description = form.description.data
        user.position = form.position.data
        print(form.position.data)
        user.organization = form.organization.data
        if is_filled(form.password.data):
            user.set_password(form.password.data)

        if is_filled(form.profile_image.data):
            filename = photos.save(form.profile_image.data)
            user.filename = filename

        db.session.commit()
        flash("We've updated your profile page!")
    return render_template('user/profile.html', form=form)


